```protobuf
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service FollowService {
  rpc Follow(FollowRequest) returns (FollowResponse);
  rpc Unfollow(UnfollowRequest) returns (UnfollowResponse);
  rpc IsFollowing(IsFollowingRequest) returns (IsFollowingResponse);
  rpc GetFollowings(GetFollowingsRequest) returns (GetFollowingsResponse);
  rpc GetFollowers(GetFollowersRequest) returns (GetFollowersResponse);
}

message Follow {
  string id = 1;
  string follower_id = 2;
  string followee_id = 3;
  int32 status = 4;
  string created_at = 5;
  string updated_at = 6;
}

message FollowRequest {
  string follower_id = 1;
  string followee_id = 2;
}

message FollowResponse {
  Follow follow = 1;
}
