### 9. GraphQL Controller

**파일 위치**: `graphql/src/main/kotlin/com/maum/backend/controller/user/FollowController.kt`

```kotlin
@Controller
class FollowController(
    private val followService: FollowService,
    private val userService: UserService,
) {
    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun follow(
        @UserId followerId: String,
        @Argument input: FollowInput,
    ): Follow {
        val response = followService.follow(followerId, input.followeeId)
        return response.follow.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun isFollowing(
        @UserId userId: String,
        @Argument followeeId: String,
    ): Boolean {
        return followService.isFollowing(userId, followeeId).isFollowing
    }
}
```

