@ExtendWith(MockitoExtension::class)
class FollowServiceTest {

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var followService: FollowService

    @Test
    fun `should follow successfully`() {
        // given
        val followerId = "user-1"
        val followeeId = "user-2"
        val followEntity = FollowEntity(
            id = "follow-1",
            followerId = followerId,
            followeeId = followeeId,
            status = 0
        )
        `when`(followRepository.save(any())).thenReturn(followEntity)

        // when
        val result = followService.follow(followerId, followeeId)

        // then
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followeeId).isEqualTo(followeeId)
        verify(followRepository).save(any())
    }

    @Test
    fun `should return true when following`() {
        // given
        val followerId = "user-1"
        val followeeId = "user-2"
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when
        val result = followService.isFollowing(followerId, followeeId)

        // then
        assertThat(result).isTrue()
    }
}
```

